def getOrderById(id: String) = Action.async { implicit request =>
  val user = request.user // Assume user is extracted from auth middleware
  OrderRepository.findById(id).map {
    case Some(order) if order.userId == user.id => 
      // Only return fields the user is authorized to see
      val sanitizedOrder = Order(
        id = order.id,
        userId = order.userId,
        items = order.items,
        total = order.total,
        status = order.status
      )
      Ok(Json.toJson(sanitizedOrder))
    case Some(_) => 
      // User doesn't own this order - return 404 to avoid leaking existence
      NotFound(Json.obj("error" -> "Order not found"))
    case None => NotFound(Json.obj("error" -> "Order not found"))
  }
